import aiocoap

class CoAPServer(aiocoap.Resource):
    def __init__(self, sensors, actuators):
        self.sensors = sensors
        self.actuators = actuators

    async def render_get(self, request):
        if request.path == "/sensors/temp":
            return aiocoap.Content("Temperature: %s" % self.sensors["temperature"])
        elif request.path == "/actuators/light":
            return aiocoap.Content("Light state: %s" % self.actuators["light"])
        else:
            return aiocoap.NotFound()

    async def render_put(self, request):
        if request.path == "/sensors/temp":
            self.sensors["temperature"] = float(request.payload)
            return aiocoap.Content("Temperature updated to %s" % self.sensors["temperature"])
        elif request.path == "/actuators/light":
            self.actuators["light"] = bool(request.payload)
            return aiocoap.Content("Light state updated to %s" % self.actuators["light"])
        else:
            return aiocoap.NotFound()

async def main():
    sensors = {"temperature": 25}
    actuators = {"light": False}
    server = CoAPServer(sensors, actuators)
    await server.start()